// 控件ID分组（按功能模块）
var CONTROL_GROUPS = {
    // 画面控制
    image: ['consoleBrightness', 'consoleContrast', 'consoleSaturation', 'consoleSharpness',
            'wbMode', 'wbRed', 'wbBlue', 'dnrSpatial', 'dnrTemporal',
