        function connectDeviceWithCreds(ip, username, password, port) {
            apiPost('/api/v1/devices/' + ip + '/connect', {
                username: username, password: password, port: port
            }).then(function(result) {
                if (result && result.success) {
                    showToast('success', '设备已连接: ' + ip);
                    addLog('success', result.message || '连接成功');
                    refreshDevices();
                    refreshPtzDeviceList();
                    refreshAdvancedDeviceSelectors();
                    // --- v3: Update global window.connectedDevice ---
                    var dev = allDevices.find(function(d) { return d.ip === ip; });
                    if (dev) {
                        window.connectedDevice = window.connectedDevice = {
                            ip: dev.ip, model: dev.model || '', name: dev.name || '', device_name: dev.device_name || '',
                            mac: dev.mac || '', username: username, password: password, port: port, online: true
                        };
                        addLog('info', '已连接设备: ' + window.connectedDevice.ip);
                        // 动态加载设备图像参数
                        setTimeout(function() {
                            console.log('[CONNECT2] Calling loadDeviceImageParams for:', ip);
                            if (typeof loadDeviceImageParams === 'function') {
                                loadDeviceImageParams(ip);
                            }
                        }, 500);
                        // WASM SDK login - user clicked Connect
                        if (window.clickLogin2) { window.clickLogin2(); }
                              if (window.updateDeviceStatus) window.updateDeviceStatus();
                    }
                } else {
                    showToast('error', result ? result.message : '连接失败');
                }
            }).catch(function(e) {
                showToast('error', '连接异常: ' + e.message);
            });
        }
        function disconnectDevice(ip) {
            // v6.54: 防止重复点击
            if (_connectionOperationInProgress) {
