async def get_connected_device() -> dict:
    """v7.10: 获取当前连接状态和上次连接设备信息。
    
    返回:
    - connected: 当前是否已连接（基于 active_device）
    - device: 上次连接的设备信息（基于 last_connected，用于快速连接）
