@app.api_route("/ISAPI/{path:path}", methods=["GET", "POST", "PUT", "DELETE"])
async def isapi_proxy(request: Request, path: str):
    global _isapi_session

    # v7.24: Get device credentials from PTZManager's connected device
    camera_ip = "192.168.5.72"
    camera_port = 80
    username = "admin"
    password = ""

    # Try to get credentials from PTZManager
    mgr = _managers.get("ptz_manager")
    if mgr:
        device = mgr.get_connected_device()
        if device:
            camera_ip = device.get('ip', camera_ip)
            camera_port = device.get('port', camera_port)
            username = device.get('username', username)
            password = device.get('password', password)

    target_url = f"http://{camera_ip}:{camera_port}/ISAPI/{path}"
    query_string = str(request.query_params)
    if query_string:
        target_url += f"?{query_string}"

    try:
        body = await request.body()

        # v7.24: Use requests with Digest auth (Hikvision cameras require Digest)
        import requests
        from requests.auth import HTTPDigestAuth

        # Forward headers
        headers = {}
        for k, v in request.headers.items():
            if k.lower() not in ["host", "content-length", "transfer-encoding", "authorization", "cookie"]:
                headers[k] = v

        # Add sessionTag if device has one (from WASM SDK device_set)
        for d in app.state.device_set if hasattr(app.state, 'device_set') else []:
            if d.szIP == camera_ip and hasattr(d, 'sessionTag') and d.sessionTag:
                headers['sessionTag'] = d.sessionTag
                break

        # Rewrite sessionLogin response to disable sessionTag requirement
        if 'sessionLogin' in path and request.method == 'POST':
            resp = requests.request(
                method=request.method, url=target_url, headers=headers,
                data=body, auth=HTTPDigestAuth(username, password), timeout=30
            )
            resp_body = resp.content
            # Fix sessionTag bug
            if 'isNeedSessionTag>true' in resp_body.decode('utf-8', errors='ignore'):
                resp_body = resp_body.decode('utf-8').replace('isNeedSessionTag>true', 'isNeedSessionTag>false').encode()
                log.info("Fixed sessionLogin: isNeedSessionTag=false")
            return Response(content=resp_body, status_code=resp.status_code, headers=dict(resp.headers))
        else:
            resp = requests.request(
                method=request.method, url=target_url, headers=headers,
                data=body, auth=HTTPDigestAuth(username, password), timeout=30
            )
            return Response(content=resp.content, status_code=resp.status_code, headers=dict(resp.headers))
    except Exception as e:
        log.error(f"ISAPI proxy error: {e}")
        return Response(content=f"Proxy error: {e}".encode(), status_code=502)

